# Security Design Principle: Least Privilege
# Users should only have the minimum permissions needed for their role

class User:
    def __init__(self, username, role):
        self.username = username
        self.role = role

# Define permission sets for each role - users only get what they need
ROLE_PERMISSIONS = {
    'viewer': {'read'},           # Can only view data
    'editor': {'read', 'write'},  # Can read and write, but not delete
    'admin': {'read', 'write', 'delete', 'admin'}
}

class SecureFileSystem:
    def __init__(self):
        self.files = {}
        self.user_permissions = ROLE_PERMISSIONS

    def check_permission(self, user, required_permission):
        """Complete Mediation: Every access is checked"""
        if user.role not in self.user_permissions:
            return False
        return required_permission in self.user_permissions[user.role]

    def read_file(self, user, filename):
        if self.check_permission(user, 'read'):
            return self.files.get(filename, "File not found")
        raise PermissionError(f"User {user.username} lacks read permission")

    def write_file(self, user, filename, content):
        if self.check_permission(user, 'write'):
            self.files[filename] = content
            return "File written successfully"
        raise PermissionError(f"User {user.username} lacks write permission")

# Usage demonstration
filesystem = SecureFileSystem()
viewer = User("john_doe", "viewer")
editor = User("jane_smith", "editor")

print(f"User: {viewer.username}, Role: {viewer.role}")
try:
    filesystem.write_file(viewer, "secret.txt", "data")
except PermissionError as e:
    print(f"BLOCKED: {e}")  # Correctly blocked - viewer has no write permission

print(f"User: {editor.username}, Role: {editor.role}")
print(filesystem.write_file(editor, "report.txt", "content"))  # Allowed
